class Solution {
public:
    int maxPalindromes(string s, int k) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + k - 1; j < n; j++) {
                string substr = s.substr(i, j - i + 1);
                if (isPalindrome(substr)) {
                    res++;
                }
            }
        }
        return res;
    }

    bool isPalindrome(string s) {
        int n = s.size();
        for (int i = 0; i < n / 2; i++) {
            if (s[i] != s[n - i - 1]) {
                return false;
            }
        }
        return true;
    }
};
```

